// [AGENT] Prep — Orchestrate Content Generation
// Calls existing webhooks: process assets -> generate scripts -> generate platform copy
try {
  const items = $('Fetch Plan + Assets').all();
  const webhookInput = $('Webhook').first().json.body;
  const planId = webhookInput.plan_id;
  const baseUrl = ($env.WEBHOOK_URL || 'https://ad-pilot-n8n-development.up.railway.app/').replace(/\/$/, '') + '/webhook';
  const assets = items.map(item => item.json);

  if (assets.length === 0) {
    return [{ json: { success: true, plan_id: planId, client_name: 'Unknown', errors: [], results: { processed: 0, scripts: 0, copy: 0 }, scriptUpdateSql: 'SELECT 1', skipped: true } }];
  }

  const clientName = assets[0].client_name || '';
  const clientId = assets[0].client_id;
  const themeName = assets[0].theme_name || '';
  const planStatus = assets[0].status;

  if (planStatus === 'scripts_ready' || planStatus === 'prep_failed') {
    return [{ json: { success: true, plan_id: planId, client_name: clientName, errors: [], results: { processed: 0, scripts: 0, copy: 0 }, scriptUpdateSql: 'SELECT 1', skipped: true, reason: 'Already ' + planStatus } }];
  }

  const videoAssets = assets.filter(a => a.asset_type === 'video');
  const imageAssets = assets.filter(a => a.asset_type === 'image');
  const carouselAssets = assets.filter(a => a.asset_type === 'carousel');
  const allAssets = [...videoAssets, ...imageAssets, ...carouselAssets];
  const errors = [];
  const results = { processed: 0, scripts: 0, copy: 0 };
  const scriptTexts = {};
  const scriptResults = {};

  // Step 1: Process Video Assets
  for (const asset of videoAssets) {
    try {
      let endpoint;
      switch (asset.template_type) {
        case 'multi_item': endpoint = '/process-multi-item-asset'; break;
        case 'spotlight': endpoint = '/process-spotlight-asset'; break;
        case 'educational': endpoint = '/process-educational-asset'; break;
        default: errors.push('Unknown template_type ' + asset.template_type + ' for ' + asset.asset_id); continue;
      }
      const resp = await fetch(baseUrl + endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ asset_id: asset.asset_id }) });
      if (!resp.ok) { errors.push('Process ' + asset.template_type + ' failed for ' + asset.asset_id + ': HTTP ' + resp.status); }
      else { results.processed++; }
    } catch (err) { errors.push('Process error ' + asset.asset_id + ': ' + err.message); }
  }

  // Step 2: Generate Scripts for Video Assets
  for (const asset of videoAssets) {
    try {
      const resp = await fetch(baseUrl + '/generate-script-from-asset', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ asset_id: asset.asset_id }) });
      const text = await resp.text();
      if (!text || !text.trim()) { errors.push('Script empty for ' + asset.asset_id); continue; }
      let data;
      try { data = JSON.parse(text); } catch (e) { errors.push('Script non-JSON for ' + asset.asset_id); continue; }
      const result = Array.isArray(data) ? data[0] : data;
      scriptResults[asset.asset_id] = result;
      const script = result.script || {};
      const fullScript = script.full_script || [script.hook, ...(script.segments || []).map(s => s.narration || s.text || s), script.cta].filter(Boolean).join(' ');
      if (fullScript) { scriptTexts[asset.asset_id] = fullScript; results.scripts++; }
    } catch (err) { errors.push('Script error ' + asset.asset_id + ': ' + err.message); }
  }

  // Step 3: Generate Platform Copy for All Assets
  for (const asset of allAssets) {
    try {
      const isVideo = asset.asset_type === 'video';
      const sr = scriptResults[asset.asset_id] || {};
      let platforms;
      try { platforms = typeof asset.placements === 'string' ? JSON.parse(asset.placements) : (asset.placements || []); } catch (e) { platforms = ['meta_feed']; }
      if (!isVideo) { platforms = platforms.filter(p => /meta|facebook|instagram/i.test(p)); if (!platforms.length) platforms = ['meta_feed']; }
      const payload = {
        client_id: clientId, platforms,
        content_type: asset.template_type === 'educational' ? 'organic' : 'ad',
        format: isVideo ? 'video' : asset.asset_type,
        template_type: sr.template_code || asset.template_type || '',
        theme: themeName, vehicles: sr.vehicles || [],
        script: isVideo ? (scriptTexts[asset.asset_id] || asset.script_text || '') : '',
        plan_asset_id: asset.asset_id, store_copy: true,
      };
      const resp = await fetch(baseUrl + '/generate-platform-copy', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
      if (!resp.ok) { errors.push('Copy failed for ' + asset.asset_id + ': HTTP ' + resp.status); }
      else { results.copy++; }
    } catch (err) { errors.push('Copy error ' + asset.asset_id + ': ' + err.message); }
  }

  // Build SQL for saving scripts
  let scriptUpdateSql = 'SELECT 1';
  const entries = Object.entries(scriptTexts);
  if (entries.length > 0) {
    scriptUpdateSql = entries.map(([id, txt]) => "UPDATE assets SET script_text = $adpilot$" + txt + "$adpilot$, updated_at = NOW() WHERE id = '" + id + "'::uuid").join(';\n') + ';';
  }

  const success = errors.length === 0 || results.copy > 0;
  return [{ json: { success, plan_id: planId, client_name: clientName, results, errors, total_assets: allAssets.length, video_count: videoAssets.length, scriptUpdateSql } }];
} catch (fatalError) {
  const planId = $('Webhook').first().json.body.plan_id || 'unknown';
  return [{ json: { success: false, plan_id: planId, client_name: 'Unknown', errors: ['Fatal: ' + fatalError.message], results: { processed: 0, scripts: 0, copy: 0 }, scriptUpdateSql: 'SELECT 1' } }];
}

const data = $('Orchestrate Content Generation').first().json;
const success = data.success;
const planId = data.plan_id;
const clientName = data.client_name || 'Unknown';
const skipped = data.skipped || false;
const status = success ? 'scripts_ready' : 'prep_failed';
const statusSql = skipped ? 'SELECT 1' : "UPDATE weekly_plans SET status = '" + status + "', updated_at = NOW() WHERE id = '" + planId + "'::uuid";
let subject, html;
if (skipped) {
  subject = '[Prep] Skipped for ' + clientName;
  html = '<p>Prep skipped for ' + clientName + '.</p>' + (data.reason ? '<p>Reason: ' + data.reason + '</p>' : '');
} else if (success) {
  subject = '[Prep Complete] Scripts & copy ready for ' + clientName;
  html = '<h2>Scripts & Copy Ready</h2><p><strong>Client:</strong> ' + clientName + '</p><ul><li>Processed: ' + data.results.processed + ' video assets</li><li>Scripts: ' + data.results.scripts + ' generated</li><li>Copy: ' + data.results.copy + ' generated</li></ul><p>Status: <strong>' + status + '</strong></p>';
} else {
  subject = '[Prep Failed] Content generation failed for ' + clientName;
  html = '<h2>Prep Pipeline Failed</h2><p><strong>Client:</strong> ' + clientName + '</p><ul>' + (data.errors || []).map(e => '<li>' + e + '</li>').join('') + '</ul><p>Status: <strong>' + status + '</strong></p>';
}
return [{ json: {
  ...data, final_status: status, statusSql,
  _emailBody: { from: 'Ad Pilot <notifications@ad-pilot.ai>', to: ['kelly@ad-pilot.ai'], subject, html },
  _response: { success, plan_id: planId, status, results: data.results, errors: data.errors || [] },
}}];

